import React from 'react';
import './ErrorMessage.css';

const ErrorMessage = ({ message, onClose }) => {
  if (!message) return null;

  return (
    <div className="error-container">
      <a href="https://www.youtube.com/watch?v=KR7rdSIyB08" target="_blank" rel="noopener noreferrer">
        <header className="top-header"></header>

        {/* Dust particles */}
        <div className="dust-particles">
          <div className="starsec"></div>
          <div className="starthird"></div>
          <div className="starfourth"></div>
          <div className="starfifth"></div>
        </div>
        {/* Dust particle end */}

        <div className="lamp__wrap">
          <div className="lamp">
            <div className="cable"></div>
            <div className="cover"></div>
            <div className="in-cover">
              <div className="bulb"></div>
            </div>
            <div className="light"></div>
          </div>
        </div>
        {/* END Lamp */}

        <section className="error">
          {/* Content */}
          <div className="error__content">
            <div className="error__message message">
              <h1 className="message__title">Oops! Something Went Wrong</h1>
              <p className="message__text">{message}</p>
              {onClose && (
                <button
                  onClick={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    onClose();
                  }}
                  className="close-btn"
                >
                  × Close
                </button>
              )}
            </div>
            <div className="error__nav e-nav">
              <span className="e-nav__link">Click anywhere to continue</span>
            </div>
          </div>
          {/* END Content */}
        </section>
      </a>
    </div>
  );
};

export default ErrorMessage;
